responses.SPARQL:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

ASK {
  pizza:FourCheesePizza rdfs:subClassOf pizza:VegetarianPizza .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

ASK {
  pizza:HamTopping owl:disjointWith pizza:AnchovyTopping .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

SELECT ?pizza WHERE {
  ?pizza owl:disjointWith [ pizza:hasBase pizza:ThinAndCrispyBase ] .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

SELECT ?pizza WHERE {
  ?pizza rdfs:subClassOf [
    owl:onProperty pizza:hasTopping ;
    owl:cardinality 2
  ] .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

ASK {
  pizza:QuattroFormaggiPizza rdfs:subClassOf pizza:CheesePizza .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

ASK {
  pizza:VenezianaPizza rdfs:subClassOf pizza:VegetarianPizza .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

ASK {
  pizza:SeafoodPizza owl:disjointWith pizza:VegetarianPizza .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>
SELECT ?topping WHERE {
  ?topping owl:disjointWith ?meat .
  ?meat rdfs:subClassOf pizza:MeatTopping .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

SELECT ?pizza WHERE {
  ?pizza owl:disjointWith ?class .
  ?class rdfs:subClassOf [ owl:onProperty pizza:hasTopping ; owl:hasValue pizza:CheeseTopping ] .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

SELECT ?pizza WHERE {
  ?pizza owl:equivalentClass [
    owl:intersectionOf (
      pizza:Pizza
      [ owl:onProperty pizza:hasTopping ;
        owl:allValuesFrom [
          owl:intersectionOf (
            pizza:SpicyTopping
          )
        ]
      ]
    )
  ] .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

ASK {
  pizza:ItalianPizza owl:disjointWith pizza:AmericanPizza .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

SELECT ?pizza WHERE {
  ?pizza owl:equivalentClass [
    owl:intersectionOf (
      pizza:Pizza
      [ owl:onProperty pizza:hasTopping ;
        owl:allValuesFrom [
          owl:complementOf pizza:MeatTopping
        ]
      ]
    )
  ] .
}

PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>
SELECT ?topping WHERE {
  ?pizza rdfs:subClassOf pizza:SeafoodPizza ;
         pizza:hasTopping ?topping .
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>
SELECT ?pizza WHERE {
  ?pizza owl:equivalentClass [ owl:intersectionOf ?restrictions ] .
  FILTER EXISTS {
    ?pizza pizza:hasTopping ?t1 .
    ?pizza pizza:hasTopping ?t2 .
    ?pizza pizza:hasTopping ?t3 .
    ?pizza pizza:hasTopping ?t4 .
    FILTER(?t1 != ?t2 && ?t1 != ?t3 && ?t1 != ?t4 && ?t2 != ?t3 && ?t2 != ?t4 && ?t3 != ?t4)
  }
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX pizza: <http://www.co-ode.org/ontologies/pizza/pizza.owl#>

SELECT ?pizza WHERE {
  ?pizza owl:equivalentClass [
    owl:intersectionOf (
      [ owl:onProperty pizza:hasTopping ;
        owl:someValuesFrom pizza:FishTopping
      ]
      [ owl:onProperty pizza:hasTopping ;
        owl:allValuesFrom [
          owl:complementOf pizza:CheeseTopping
        ]
      ]
    )
  ] .
}
